user_prompt:
任务输入:
- 训练任务描述: SVRDD 道路路面病害检测数据集目标检测训练，7 类别分类，使用 YOLO26n 轻量模型，小分辨率 320x320 快速验证
- 指标要求: 无特殊要求
- 资源/时间约束: 无特殊约束

请分析该训练任务的场景特征。

请严格按照以下JSON Schema输出，只输出合法JSON本身，不要用```代码块包裹，不要输出任何多余的解释性文字：
{
  "description": "Scenario-Analysis Agent产出：任务类型/行业/难度/风险等场景理解。",
  "properties": {
    "task_type": {
      "description": "任务类型，如 llm-sft / cv-detect / cv-segment 等",
      "title": "Task Type",
      "type": "string"
    },
    "industry": {
      "description": "应用行业/领域",
      "title": "Industry",
      "type": "string"
    },
    "difficulty": {
      "description": "任务难度评估",
      "enum": [
        "low",
        "medium",
        "high"
      ],
      "title": "Difficulty",
      "type": "string"
    },
    "latency_constraint": {
      "description": "推理速度约束描述，无特殊要求可填'无'",
      "title": "Latency Constraint",
      "type": "string"
    },
    "priority_suggestion": {
      "description": "优先级建议",
      "title": "Priority Suggestion",
      "type": "string"
    },
    "risks": {
      "description": "潜在风险提示列表",
      "items": {
        "type": "string"
      },
      "title": "Risks",
      "type": "array"
    },
    "citations": {
      "description": "WebSearch/WebFetch检索到的引用来源(URL/标题)",
      "items": {
        "type": "string"
      },
      "title": "Citations",
      "type": "array"
    }
  },
  "required": [
    "task_type",
    "industry",
    "difficulty",
    "latency_constraint",
    "priority_suggestion"
  ],
  "title": "ScenarioAnalysisOutput",
  "type": "object"
}
